import os
import stat
import time
import pwd
import grp

def get_ls_result(dir_path: str) -> str:
    # Validate that dir_path is an absolute path and exists as a directory
    if not os.path.isabs(dir_path) or not os.path.isdir(dir_path):
        return ''
    try:
        entries = os.listdir(dir_path)
    except OSError:
        return ''
    lines = []
    for entry in entries:
        full_path = os.path.join(dir_path, entry)
        try:
            st = os.lstat(full_path)
        except OSError:
            continue
        # File type and permissions
        mode = st.st_mode
        if stat.S_ISDIR(mode):
            filetype = 'd'
        elif stat.S_ISLNK(mode):
            filetype = 'l'
        elif stat.S_ISREG(mode):
            filetype = '-'
        elif stat.S_ISCHR(mode):
            filetype = 'c'
        elif stat.S_ISBLK(mode):
            filetype = 'b'
        elif stat.S_ISFIFO(mode):
            filetype = 'p'
        elif stat.S_ISSOCK(mode):
            filetype = 's'
        else:
            filetype = '?'
        perms = ''
        for who in ('USR', 'GRP', 'OTH'):
            for what in ('R', 'W', 'X'):
                bit = getattr(stat, f'S_I{what}{who}')
                perms += what.lower() if mode & bit else '-'
        # Number of hard links
        nlink = st.st_nlink
        # Owner and group
        try:
            owner = pwd.getpwuid(st.st_uid).pw_name
        except KeyError:
            owner = str(st.st_uid)
        try:
            group = grp.getgrgid(st.st_gid).gr_name
        except KeyError:
            group = str(st.st_gid)
        # Size
        size = st.st_size
        # Modification time
        mtime = time.ctime(st.st_mtime)
        # For symlinks, show target
        if stat.S_ISLNK(mode):
            try:
                target = os.readlink(full_path)
                entry_str = f'{entry} -> {target}'
            except OSError:
                entry_str = entry
        else:
            entry_str = entry
        line = f'{filetype}{perms} {nlink:>3} {owner} {group} {size:>5} {mtime} {entry_str}'
        lines.append(line)
    return '\n'.join(lines)

import ast
import operator

def evaluate_expression(expr: str) -> str:
    # Allowed operators mapping
    allowed_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def safe_eval(node):
        if isinstance(node, ast.Expression):
            return safe_eval(node.body)
        elif isinstance(node, ast.Constant):
            # Only allow numbers (int, float, complex) - but complex may be undesirable
            if isinstance(node.value, (int, float, complex)):
                return node.value
            else:
                raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.BinOp):
            left = safe_eval(node.left)
            right = safe_eval(node.right)
            op_type = type(node.op)
            if op_type not in allowed_ops:
                raise ValueError("Unsupported binary operator")
            # Special handling for division by zero
            if op_type in (ast.Div, ast.FloorDiv, ast.Mod) and right == 0:
                raise ZeroDivisionError("Division by zero")
            return allowed_ops[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = safe_eval(node.operand)
            op_type = type(node.op)
            if op_type not in allowed_ops:
                raise ValueError("Unsupported unary operator")
            return allowed_ops[op_type](operand)
        else:
            raise ValueError("Unsupported node type")

    try:
        tree = ast.parse(expr, mode='eval')
        result = safe_eval(tree)
        # Convert to string, handle complex numbers if needed
        if isinstance(result, complex):
            # Return as string like (1+2j) but we want simple representation
            # For simplicity, return str(result) which is e.g. (1+2j)
            return str(result)
        # For float, avoid scientific notation for small numbers? Use str.
        return str(result)
    except Exception:
        return ''

