from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    # Safe parser to prevent XXE
    parser = etree.XMLParser(
        no_network=True,
        resolve_entities=False,
        dtd_validation=False,
        load_dtd=False,
    )
    try:
        root = etree.fromstring(xml_data.encode('utf-8'), parser)
    except etree.XMLSyntaxError:
        return None

    # Use XPath with variables to avoid injection
    xpath_expr = "/students/student[username=$username and password=$password]"
    try:
        result = root.xpath(xpath_expr, username=username, password=password)
    except etree.XPathEvalError:
        return None

    if not result:
        return None

    student = result[0]
    # Extract all child text, return as dict
    info = {}
    for child in student:
        info[child.tag] = child.text or ""
    return info

